#ifndef TOP_P_SAMPLING_KERNEL_H
#define TOP_P_SAMPLING_KERNEL_H

#include <cuda_runtime.h>
#include <stdint.h>
#include <float.h>

// Kernel launch configuration for A800
#define BLOCK_SIZE 256
#define MAX_VOCAB_SIZE 129280

// Structure to hold (prob, index) pairs for sorting
struct __align__(8) ProbIndexPair {
    float prob;
    int index;
};

// Main kernel declaration
void launchTopPSampling(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    float* temp_storage,
    cudaStream_t stream = 0
);

#endif // TOP_P_SAMPLING_KERNEL_H

#include "kernel.h"
#include <device_launch_parameters.h>
#include <math_constants.h>
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <thrust/execution_policy.h>
#include <thrust/iterator/counting_iterator.h>
#include <thrust/pair.h>

// Device-compatible XORSHIFT random number generator
struct __align__(8) XorshiftState {
    uint64_t s0;
    uint64_t s1;
    uint64_t s2;
    uint64_t s3;
};

__device__ __forceinline__ void initXorshift(XorshiftState& state, uint64_t seed) {
    state.s0 = seed;
    state.s1 = seed * 6364136223846793005ULL + 1;
    state.s2 = seed * 6364136223846793005ULL + 2;
    state.s3 = seed * 6364136223846793005ULL + 3;
}

__device__ __forceinline__ uint64_t nextXorshift(XorshiftState& state) {
    uint64_t t = state.s3;
    uint64_t s = state.s0;
    state.s3 = state.s2;
    state.s2 = state.s1;
    state.s1 = s;
    t ^= t << 17;
    t ^= t >> 13;
    t ^= s ^ (s >> 7);
    state.s0 = t;
    return t;
}

__device__ __forceinline__ float randomFloat(XorshiftState& state) {
    return static_cast<float>(nextXorshift(state)) * 2.3283064365386963e-10f;
}

// Functor for sorting - more compatible than lambda with __device__
struct ProbIndexComparator {
    __device__ bool operator()(const ProbIndexPair& a, const ProbIndexPair& b) const {
        return a.prob > b.prob;
    }
};

// Main kernel for top-p sampling - one thread per batch
__global__ void topPSamplingKernel(
    const float* __restrict__ probs,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int batch_size,
    int vocab_size,
    ProbIndexPair* temp_pairs
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    // Only use one thread per batch for simplicity and correctness
    if (threadIdx.x != 0) return;

    // Initialize random state for this batch
    XorshiftState state;
    initXorshift(state, static_cast<uint64_t>(batch_idx * 12345ULL + 54321ULL));

    // Get pointers to this batch's data
    const float* row_probs = probs + batch_idx * vocab_size;
    float p_threshold = top_p[batch_idx];

    // Pointer to this batch's temp storage
    ProbIndexPair* batch_pairs = temp_pairs + batch_idx * vocab_size;

    // Initialize pairs
    for (int i = 0; i < vocab_size; i++) {
        batch_pairs[i].prob = row_probs[i];
        batch_pairs[i].index = i;
    }

    // Handle edge case: top_p <= 0.0 means argmax
    if (p_threshold <= 0.0f) {
        float max_prob = -FLT_MAX;
        int max_idx = 0;
        for (int i = 0; i < vocab_size; i++) {
            float prob = batch_pairs[i].prob;
            if (prob > max_prob) {
                max_prob = prob;
                max_idx = batch_pairs[i].index;
            }
        }
        samples[batch_idx] = max_idx;
        return;
    }

    // Handle edge case: top_p >= 1.0 means sample from full distribution
    if (p_threshold >= 1.0f) {
        float r = randomFloat(state);
        float cumsum = 0.0f;
        int sampled_idx = vocab_size - 1;

        for (int i = 0; i < vocab_size; i++) {
            cumsum += row_probs[i];
            if (r < cumsum) {
                sampled_idx = i;
                break;
            }
        }
        samples[batch_idx] = sampled_idx;
        return;
    }

    // Sort probabilities in descending order using thrust
    thrust::device_ptr<ProbIndexPair> d_pairs(batch_pairs);
    thrust::sort(thrust::device, d_pairs, d_pairs + vocab_size,
        ProbIndexComparator());

    // Compute cumulative sum and find cutoff
    float cumsum = 0.0f;
    int cutoff_idx = vocab_size;

    for (int i = 0; i < vocab_size; i++) {
        cumsum += batch_pairs[i].prob;
        if (cumsum >= p_threshold) {
            cutoff_idx = i + 1;  // Keep this token (first that crosses p)
            break;
        }
    }

    // Compute sum of probabilities up to cutoff for normalization
    float filtered_sum = 0.0f;
    for (int i = 0; i < cutoff_idx; i++) {
        filtered_sum += batch_pairs[i].prob;
    }

    // Sample from filtered distribution
    float r = randomFloat(state);
    float cumsum_filtered = 0.0f;
    int sampled_idx = batch_pairs[0].index;

    for (int i = 0; i < cutoff_idx; i++) {
        cumsum_filtered += batch_pairs[i].prob / filtered_sum;
        if (r < cumsum_filtered) {
            sampled_idx = batch_pairs[i].index;
            break;
        }
    }

    samples[batch_idx] = sampled_idx;
}

// Host function to launch kernel
void launchTopPSampling(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    float* temp_storage,
    cudaStream_t stream
) {
    // Configure kernel launch for A800
    int block_size = 1;  // One thread per batch for correctness
    int grid_size = batch_size;

    // Launch kernel
    topPSamplingKernel<<<grid_size, block_size, 0, stream>>>(
        probs, top_p, samples, batch_size, vocab_size,
        reinterpret_cast<ProbIndexPair*>(temp_storage)
    );
}

#include <torch/extension.h>
#include "kernel.h"
#include <ATen/ATen.h>
#include <cuda_runtime.h>
#include <stdexcept>
#include <string>

// Helper function to check CUDA errors
inline void checkCudaError(cudaError_t error, const char* operation) {
    if (error != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error in ") + operation + ": " + cudaGetErrorString(error));
    }
}

// Main run function that handles torch tensors
torch::Tensor run(torch::Tensor probs, torch::Tensor top_p, torch::Tensor samples) {
    // Validate inputs
    if (!probs.device().is_cuda()) {
        throw std::runtime_error("probs tensor must be on CUDA device");
    }

    if (!top_p.device().is_cuda()) {
        throw std::runtime_error("top_p tensor must be on CUDA device");
    }

    if (!samples.device().is_cuda()) {
        throw std::runtime_error("samples tensor must be on CUDA device");
    }

    if (probs.dtype() != torch::kFloat32) {
        throw std::runtime_error("probs tensor must be of dtype float32");
    }

    if (top_p.dtype() != torch::kFloat32) {
        throw std::runtime_error("top_p tensor must be of dtype float32");
    }

    if (samples.dtype() != torch::kInt64) {
        throw std::runtime_error("samples tensor must be of dtype int64");
    }

    if (probs.dim() != 2) {
        throw std::runtime_error("probs tensor must be 2D [batch_size, vocab_size]");
    }

    if (top_p.dim() != 1) {
        throw std::runtime_error("top_p tensor must be 1D [batch_size]");
    }

    if (samples.dim() != 1) {
        throw std::runtime_error("samples tensor must be 1D [batch_size]");
    }

    int64_t batch_size = probs.size(0);
    int64_t vocab_size = probs.size(1);

    if (batch_size != top_p.size(0)) {
        throw std::runtime_error("batch_size mismatch between probs and top_p");
    }

    if (batch_size != samples.size(0)) {
        throw std::runtime_error("batch_size mismatch between probs and samples");
    }

    if (vocab_size != 129280) {
        throw std::runtime_error("vocab_size must be 129280 for DeepSeek V3");
    }

    // Allocate temporary device memory for sorting (ProbIndexPair = 8 bytes)
    size_t temp_size = batch_size * vocab_size * sizeof(float) * 2;  // 8 bytes per pair
    float* temp_storage = nullptr;
    checkCudaError(cudaMalloc(&temp_storage, temp_size), "temp_storage allocation");

    // Get raw pointers
    float* probs_ptr = probs.data_ptr<float>();
    float* top_p_ptr = top_p.data_ptr<float>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Launch kernel
    launchTopPSampling(
        probs_ptr,
        top_p_ptr,
        samples_ptr,
        static_cast<int>(batch_size),
        static_cast<int>(vocab_size),
        temp_storage,
        0  // default stream
    );

    // Check for errors after kernel launch
    checkCudaError(cudaGetLastError(), "after kernel launch");

    // Synchronize to ensure completion
    checkCudaError(cudaDeviceSynchronize(), "after kernel completion");

    // Free temporary memory
    checkCudaError(cudaFree(temp_storage), "temp_storage free");

    return samples;
}

// PYBIND11 module binding
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "Top-P Sampling Kernel for A800 GPU";
    m.def("run", &run, "Execute top-p sampling from probability distributions",
          py::arg("probs"),
          py::arg("top_p"),
          py::arg("samples"));
}
